use live
go

--select * from labor_ticket where transaction_id in ('14772443', '14772446')

select it.*, lt.*
from labor_ticket lt
inner join 
(select employee_id, UNADJ_CLOCK_IN, transaction_id, [type], [user_id]
from labor_ticket 
where [type] = 'i'
) it
on it.employee_id = lt.employee_id
and it.UNADJ_CLOCK_IN = lt.UNADJ_CLOCK_IN
where lt.[type] = 'R'
and lt.TRANSACTION_DATE >= '1/1/2018'


